import{_ as e,o as a,c as r,a2 as i}from"./chunks/framework.N6Nd-M9-.js";const g=JSON.parse('{"title":"📈 公司为什么从外出作业开始——个人成长（下）","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/六大会议/01—公司为什么从外出作业开始——个人成长（下）.md","filePath":"notes/培训/六大会议/01—公司为什么从外出作业开始——个人成长（下）.md"}'),p={name:"notes/培训/六大会议/01—公司为什么从外出作业开始——个人成长（下）.md"};function s(t,d,l,o,n,x){return a(),r("div",null,[...d[0]||(d[0]=[i('<h1 id="📈-公司为什么从外出作业开始——个人成长-下" tabindex="-1">📈 公司为什么从外出作业开始——个人成长（下） <a class="header-anchor" href="#📈-公司为什么从外出作业开始——个人成长-下" aria-label="Permalink to &quot;📈 公司为什么从外出作业开始——个人成长（下）&quot;">​</a></h1><blockquote><p>本文将帮助你深入理解相关内容，掌握核心知识。</p></blockquote><div class="tc-card tc-card-blue"><p class="tc-title tc-blue">💡 核心要点</p><p class="tc-body">本文将帮助你深入理解相关内容，掌握核心知识。</p></div><hr><h2 id="🎯-一、销售的核心-建立信任的能力-🤝" tabindex="-1">🎯 一、销售的核心：建立信任的能力 🤝 <a class="header-anchor" href="#🎯-一、销售的核心-建立信任的能力-🤝" aria-label="Permalink to &quot;🎯 一、销售的核心：建立信任的能力 🤝&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">💎 本质定义</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">销售不仅是卖货，更是<strong class="tc-blue">&quot;让人心甘情愿在短时间内（3-5分钟）交钱&quot;</strong>的能力。这是一种高价值的&quot;与人打交道&quot;的能力，区别于非法手段。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">📋 真实案例</p><p class="tc-body" style="font-size:14px;margin:0 0 6px 0;line-height:1.6;"><strong class="tc-blue">POS机推广</strong>：客户因信任业务员，仅见一面便转账数万元用于周转。</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;"><strong class="tc-blue">紧急救援</strong>：客户手机丢失，直接扫业务员码临时周转资金。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">✅ 结论</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">这种深度的信任感，是销售人员的<strong class="tc-blue">立身之本</strong>。</p></div></div></div><h2 id="🏃-二、跑业务-外勤-成长的必经之路-🏃‍♂️" tabindex="-1">🏃 二、跑业务（外勤）：成长的必经之路 🏃‍♂️ <a class="header-anchor" href="#🏃-二、跑业务-外勤-成长的必经之路-🏃‍♂️" aria-label="Permalink to &quot;🏃 二、跑业务（外勤）：成长的必经之路 🏃‍♂️&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 10px 0;">🏃 身体考验</p><p class="tc-body" style="font-size:14px;margin:0 0 8px 0;line-height:1.6;">日晒雨淋、持续奔波是常态。无法忍受跑业务的辛苦（如&quot;跑一天就歇火&quot;）的人会被淘汰。</p></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 10px 0;">🧠 心智考验</p><p class="tc-body" style="font-size:14px;margin:0 0 8px 0;line-height:1.6;">拒绝舒适区（坐办公室）。面试时，<strong class="tc-blue">不接受外勤的人直接Pass</strong>。</p></div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 10px 0;">🎯 跑业务的真正目的</p><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:10px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:250px;border-left:4px solid #667eea;"><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">不是为了跑一辈子，而是为了<strong class="tc-blue">通过市场实战学习技能</strong>（口才、胆量、心态、带队）。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:250px;border-left:4px solid #667eea;"><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;"><strong class="tc-blue">对比</strong>：真正的经理是全能型（销售+人事+财务+培训），而非&quot;挂名经理&quot;。</p></div></div></div></div><h2 id="⬆️-三、晋升逻辑-想法-做法-结果-📈" tabindex="-1">⬆️ 三、晋升逻辑：想法 + 做法 + 结果 📈 <a class="header-anchor" href="#⬆️-三、晋升逻辑-想法-做法-结果-📈" aria-label="Permalink to &quot;⬆️ 三、晋升逻辑：想法 + 做法 + 结果 📈&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:200px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 8px 0;">💡 想法</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">要有&quot;当将军&quot;的野心（&quot;不想当将军的士兵不是好士兵&quot;）。</p></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:200px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 8px 0;">🛠️ 做法</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">接受外勤考验，展现生存和学习能力。</p></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;flex:1;min-width:200px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="font-size:16px;margin:0 0 8px 0;">🏆 结果</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">用&quot;丰功伟绩&quot;（业绩、战果）证明实力。</p></div></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:15px;border-radius:12px;margin:20px 0;"><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">⚠️ <strong class="tc-red">淘汰机制</strong>：业务稀碎、心态易崩的人无法胜任管理岗位。</p></div><h2 id="📈-四、成长四阶段-从士兵到将军-⚔️" tabindex="-1">📈 四、成长四阶段：从士兵到将军 ⚔️ <a class="header-anchor" href="#📈-四、成长四阶段-从士兵到将军-⚔️" aria-label="Permalink to &quot;📈 四、成长四阶段：从士兵到将军 ⚔️&quot;">​</a></h2><div style="display:flex;flex-direction:column;gap:12px;margin:20px 0;"><div class="tc-body" style="display:flex;align-items:center;gap:15px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:18px 20px;border-radius:12px;"><div class="tc-blue tc-bold" style="background:rgba(102,126,234,0.15);padding:10px 18px;border-radius:10px;font-size:16px;white-space:nowrap;">第一阶段</div><div style="flex:1;"><p class="tc-bold" style="margin:0;font-size:18px;">🎖️ 自己做销售</p><p style="margin:5px 0 0 0;font-size:14px;">活下来，掌握基础技能（上战场杀敌）</p></div></div><div class="tc-body" style="display:flex;align-items:center;gap:15px;background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:18px 20px;border-radius:12px;"><div class="tc-green tc-bold" style="background:rgba(34,197,94,0.15);padding:10px 18px;border-radius:10px;font-size:16px;white-space:nowrap;">第二阶段</div><div style="flex:1;"><p class="tc-bold" style="margin:0;font-size:18px;">👥 教别人做销售</p><p style="margin:5px 0 0 0;font-size:14px;">以身作则，生命影响生命（带新兵）</p></div></div><div class="tc-body" style="display:flex;align-items:center;gap:15px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.15);padding:18px 20px;border-radius:12px;"><div class="tc-orange tc-bold" style="background:rgba(245,158,11,0.15);padding:10px 18px;border-radius:10px;font-size:16px;white-space:nowrap;">第三阶段</div><div style="flex:1;"><p class="tc-bold" style="margin:0;font-size:18px;">🎯 教别人&quot;教销售&quot;</p><p style="margin:5px 0 0 0;font-size:14px;">培养骨干，团队中有2+合格组长</p></div></div><div class="tc-body" style="display:flex;align-items:center;gap:15px;background:rgba(236,72,153,0.06);border:1px solid rgba(236,72,153,0.15);padding:18px 20px;border-radius:12px;"><div class="tc-pink tc-bold" style="background:rgba(236,72,153,0.15);padding:10px 18px;border-radius:10px;font-size:16px;white-space:nowrap;">第四阶段</div><div style="flex:1;"><p class="tc-bold" style="margin:0;font-size:18px;">👑 通过培训教销售</p><p style="margin:5px 0 0 0;font-size:14px;">脱离一线，通过会议/培训指挥全局（将军指挥战斗）</p></div></div></div><h2 id="🎯-五、长期目标-打造自己的事业-🏆" tabindex="-1">🎯 五、长期目标：打造自己的事业 🏆 <a class="header-anchor" href="#🎯-五、长期目标-打造自己的事业-🏆" aria-label="Permalink to &quot;🎯 五、长期目标：打造自己的事业 🏆&quot;">​</a></h2><div style="display:flex;flex-wrap:wrap;gap:12px;margin:20px 0;"><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;border-left:4px solid #ef4444;"><p class="tc-red tc-bold" style="font-size:16px;margin:0 0 10px 0;">😔 普通打工</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">替人干活，时间不自由，无归属感。</p></div></div><div style="background:rgba(34,197,94,0.06);border:1px solid rgba(34,197,94,0.15);padding:20px;border-radius:12px;flex:1;min-width:300px;"><div style="background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;border-left:4px solid #22c55e;"><p class="tc-green tc-bold" style="font-size:16px;margin:0 0 10px 0;">🚀 销售积累</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">3-5年沉淀后，可组建自己的销售公司，实现时间自由和资产积累。</p></div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:15px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">🔑 <strong>底层逻辑</strong>：任何职业若能通向&quot;拥有自己的产业&quot;（如保安→保安公司），都值得投入。<strong class="tc-blue">销售的优势在于能力可直接转化为商业资本</strong>。</p></div></div><h2 id="💪-六、面对挑战-痛苦是成功的垫脚石-🛡️" tabindex="-1">💪 六、面对挑战：痛苦是成功的垫脚石 🛡️ <a class="header-anchor" href="#💪-六、面对挑战-痛苦是成功的垫脚石-🛡️" aria-label="Permalink to &quot;💪 六、面对挑战：痛苦是成功的垫脚石 🛡️&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="display:flex;flex-wrap:wrap;gap:12px;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">🌪️ 外部磨难</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">被拒绝、被嘲讽（&quot;小趴菜&quot;）、业绩低谷。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">💔 内部磨难</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">牺牲个人时间（周末/节日团建）、家人不理解、感情受挫。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;flex:1;min-width:280px;border-left:4px solid #667eea;"><p class="tc-blue tc-bold" style="margin:0 0 8px 0;">💪 心态建设</p><p class="tc-body" style="font-size:14px;margin:0;line-height:1.6;">所有成功人士都经历过&quot;身心双重痛苦&quot;。唯有坚持目标，用结果证明自己，才能从士兵成长为将军。</p></div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:20px;border-radius:12px;margin:20px 0;"><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;border-left:4px solid #667eea;"><p class="tc-body tc-bold" style="font-size:15px;margin:0;line-height:1.7;">📌 <strong>总结</strong>：销售 = 建立信任的能力。跑业务 = 成长的试金石。用&quot;想法+做法+结果&quot;铺路，最终目标是<strong class="tc-blue">拥有属于自己的事业</strong>。</p></div></div>',20)])])}const c=e(p,[["render",s]]);export{g as __pageData,c as default};
